const Q_COMPUTER_STUDIES_2025_MODEL_I=[{"id": "objective>Computer Studies>2025 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following storage devices is non-volatile and uses flash memory technology?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SSD (Solid State Drive)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RAM (Random Access Memory)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cache Memory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Optical Disc</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An SSD (Solid State Drive) uses flash memory technology, which is a type of non-volatile memory. This means it retains stored data even when the power is turned off. Flash memory allows for fast data access and retrieval without any moving parts, making SSDs much faster and more durable than traditional hard drives. <br/>  <br/> RAM and cache memory are volatile, losing their data when power is lost. Optical discs (like CDs and DVDs) are non-volatile but do not use flash memory technology—they store data using laser-etched patterns on their surface.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TYPE, EXAMPLES AND USES OF COMPUTER HARDWARE"}, {"id": "objective>Computer Studies>2025 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which hardware type facilitates communication between different internal components of a computer?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monitor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Keyboard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CPU</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A bus is a communication system within a computer that transfers data between internal components such as the CPU, memory, and peripheral devices. It consists of multiple wires or traces that carry data, addresses, and control signals. <br/>  <br/> The CPU processes data, but it relies on the bus to communicate with other components. A monitor and keyboard are input/output devices and do not facilitate internal component communication. Thus, the bus is the key hardware that enables different parts of the computer to communicate efficiently.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TYPE, EXAMPLES AND USES OF COMPUTER HARDWARE"}, {"id": "objective>Computer Studies>2025 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A user is building a new computer and needs a primary storage device that provides fast boot times and rapid application loading. What type of device should they choose, and why is it better for this purpose than a traditional hard drive?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A Solid-State Drive (SSD), because it uses flash memory with no moving parts, allowing for much faster data access and retrieval.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A Hard Disk Drive (HDD), because its spinning platters can access data more quickly than an SSD.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A Solid-State Drive (SSD), because it has a larger storage capacity than a Hard Disk Drive.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A Hard Disk Drive (HDD), because it is more durable and resistant to physical shock than an SSD.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An SSD uses flash memory chips to store data, which means it can access and transfer data almost instantly without the mechanical delays caused by moving parts. This lack of moving components results in significantly faster boot times and quicker application loading compared to traditional Hard Disk Drives (HDDs), which rely on spinning magnetic platters and mechanical read/write heads. HDDs are slower because the read/write heads must physically move to the location of data on the spinning disks, causing latency. While HDDs often offer larger storage at a lower cost, for performance-critical tasks like booting and launching software, SSDs provide a clear advantage due to their speed and responsiveness.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TYPE, EXAMPLES AND USES OF COMPUTER HARDWARE"}, {"id": "objective>Computer Studies>2025 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of computer hardware is used primarily for temporary, high-speed data storage during active processing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Secondary Storage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cache Memory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Optical Disc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic Tape</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cache memory stores frequently accessed data and instructions temporarily to reduce CPU wait times and speed up processing, unlike secondary storage or optical discs, which store data persistently.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TYPE, EXAMPLES AND USES OF COMPUTER HARDWARE"}, {"id": "objective>Computer Studies>2025 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following types of memory is non-volatile but can be electrically erased and reprogrammed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ROM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PROM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EPROM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RAM</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">EPROM is a type of non-volatile memory that can be erased by exposing it to ultraviolet (UV) light and then reprogrammed electrically. This makes it flexible for updates compared to standard ROM, which is programmed once during manufacturing and cannot be changed. <br/>  <br/> PROM (Programmable ROM) can be programmed once but cannot be erased or rewritten. RAM is volatile memory, losing data when power is off. ROM is non-volatile but generally not reprogrammable. Therefore, EPROM stands out as non-volatile and reprogrammable with electrical programming after erasing.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TYPE, EXAMPLES AND USES OF COMPUTER HARDWARE"}, {"id": "objective>Computer Studies>2025 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which software layer acts as the intermediary between user applications and the computer hardware?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Application Software</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Device Drivers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Operating System</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Utility Programs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The operating system (OS) serves as the critical intermediary layer between application software and hardware. It manages hardware resources such as the CPU, memory, storage devices, and input/output peripherals. The OS provides system services, abstraction, and control, allowing application programs to run without needing to manage hardware directly. Device drivers are specialized system software that enable communication with specific hardware devices, but the OS oversees the entire system's operation. Utility programs provide maintenance functions but do not act as the core intermediary. The OS's role is central to bridging hardware capabilities and user-level software operations.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TWO MAIN CONSTITUENTS OF A COMPUTER (HARDWARE AND SOFTWARE)"}, {"id": "objective>Computer Studies>2025 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT considered part of computer hardware?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Central Processing Unit (CPU)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Operating System</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Graphics Card</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Random Access Memory (RAM)</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The operating system (OS) is software, not hardware. It is a collection of programs that manage computer hardware and provide services to other software. The CPU, graphics card, and RAM are all physical components and thus considered hardware. While hardware can be seen and touched, software like the OS exists as code and instructions stored digitally and executed by hardware.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TWO MAIN CONSTITUENTS OF A COMPUTER (HARDWARE AND SOFTWARE)"}, {"id": "objective>Computer Studies>2025 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of open-source software is:</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Microsoft Office</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adobe Photoshop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Linux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iOS</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Open-source software is software whose source code is freely available for anyone to view, modify, and distribute. Linux is a prime example of open-source software; its source code is openly published, and it is developed collaboratively by communities worldwide. Users can customize it to their needs without paying licensing fees. <br/>  <br/> In contrast, Microsoft Office, Adobe Photoshop, and iOS are proprietary software. Their source code is closed to the public, and they require users to purchase licenses to use them. These companies maintain strict control over the software's development, distribution, and usage rights.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TWO MAIN CONSTITUENTS OF A COMPUTER (HARDWARE AND SOFTWARE)"}, {"id": "objective>Computer Studies>2025 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why is binary used for data representation in computers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It matches the two states of hardware components.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It requires fewer digits than decimal.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is easier for humans to read and write.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It consumes less power during processing.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Computers are built with electronic circuits that have two stable states, typically represented as ON and OFF or high and low voltage. Binary, which consists of only two digits (0 and 1), aligns perfectly with these two physical states. This simplicity allows for more reliable, faster, and less error-prone data processing and storage. Using other number systems like decimal (base-10) would require hardware to detect and process ten distinct voltage levels, which is much more complex and prone to errors.</div>", "topic": "FUNDAMENTALS OF COMPUTING: DATA AND INFORMATION :DATA REPRESENTATION"}, {"id": "objective>Computer Studies>2025 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which encoding scheme can represent over a million different characters?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ASCII</div>", "<div style=\"font-family:Cambria;font-size:17px;\">UTF-8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unicode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EBCDIC</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unicode is a comprehensive encoding standard designed to cover all written languages, symbols, and emojis worldwide. It supports over 1.1 million code points, which makes it capable of representing characters from virtually every writing system. UTF-8 and UTF-16 are implementations of Unicode designed to encode these characters efficiently.</div>", "topic": "FUNDAMENTALS OF COMPUTING: DATA AND INFORMATION :DATA REPRESENTATION"}, {"id": "objective>Computer Studies>2025 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true about an XOR gate?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It outputs HIGH when all inputs are HIGH.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It outputs HIGH when the number of HIGH inputs is odd.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It outputs HIGH when all inputs are LOW.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It always outputs the same as one of the inputs.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An XOR (exclusive OR) gate outputs HIGH if an odd number of inputs are HIGH. For two inputs, this means output is HIGH only when exactly one input is HIGH. This gate is useful for parity checking and binary addition (as a half-adder component).</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:LOGIC CIRCUITS"}, {"id": "objective>Computer Studies>2025 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What does it mean when a logic gate is called a 'universal gate'?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It can be used to perform both digital and analog operations.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can implement any Boolean function by itself.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It only requires one input to operate.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It produces outputs in multiple voltage levels.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NAND and NOR gates are called universal gates because any logic function, including AND, OR, and NOT, can be constructed by combining multiple NAND or NOR gates alone. This property is essential in digital design for simplifying circuit fabrication.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:LOGIC CIRCUITS"}, {"id": "objective>Computer Studies>2025 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An individual is accessing a public Wi-Fi network and is concerned about the possibility of a Man-in-the-Middle (MITM) attack. Which of the following is the most effective way for the user to mitigate this risk?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Only visiting websites that use the HTTPS protocol.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Using a strong, unique password for all their online accounts.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Using a Virtual Private Network (VPN) for all network traffic.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Disabling the computer's firewall while on the public network.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Man-in-the-Middle (MITM) attack occurs when an attacker secretly intercepts and possibly alters communication between two parties without their knowledge. Public Wi-Fi networks are particularly vulnerable because they are often unsecured, allowing attackers to eavesdrop on data transmitted over the network. <br/>  <br/> - While visiting only HTTPS websites helps because HTTPS encrypts data between the browser and the website, it doesn't protect all types of traffic. Some apps or websites may still use unencrypted connections, and attackers can try to intercept or spoof HTTPS certificates. <br/>  <br/> - Using strong, unique passwords is important for overall account security but does not prevent MITM attacks during data transmission over the network. <br/>  <br/> - Using a Virtual Private Network (VPN) encrypts all the user's network traffic by creating a secure, encrypted tunnel to a trusted VPN server. This means even if an attacker intercepts the data on the public Wi-Fi, they cannot decipher it, effectively mitigating the risk of MITM attacks. <br/>  <br/> - Disabling the firewall reduces protection and makes the device more vulnerable to attacks, which is the opposite of what a user should do. <br/>  <br/> Thus, using a VPN provides the most comprehensive protection against MITM attacks on public Wi-Fi networks.</div>", "topic": "COMPUTER ETHICS AND HUMAN ISSUES: COMPUTER SECURITY"}, {"id": "objective>Computer Studies>2025 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company's network security team is concerned about a sophisticated attack where an attacker has manipulated data packets in transit to intercept and modify communications between two systems without either party's knowledge. Which type of attack is this team primarily concerned with?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A SQL Injection attack.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A Man-in-the-Middle (MITM) attack.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A Phishing attack.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A Distributed Denial of Service (DDoS) attack.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scenario describes an attacker intercepting and manipulating data packets exchanged between two systems without the knowledge of either party. This is the hallmark of a Man-in-the-Middle (MITM) attack. <br/>  <br/> SQL Injection: This attack targets databases by inserting malicious SQL code through user inputs to manipulate or retrieve data improperly. It does not involve intercepting communication between two systems. <br/>  <br/> MITM: A Man-in-the-Middle attack occurs when the attacker positions themselves between two communicating parties, intercepting and potentially modifying the data in transit. The parties believe they are communicating directly with each other, unaware that their information is being compromised. This aligns perfectly with the team's concern. <br/>  <br/> Phishing: Phishing attacks involve tricking users into revealing sensitive information by impersonating trustworthy entities, usually via email or fake websites. It does not involve direct manipulation of communication channels. <br/>  <br/> DDoS: A Distributed Denial of Service attack overwhelms a system with excessive traffic to make it unavailable but does not manipulate data communications between parties. <br/>  <br/> Therefore, the network security team is primarily concerned about a Man-in-the-Middle (MITM) attack because it enables attackers to secretly intercept and alter communications, compromising data integrity and confidentiality.</div>", "topic": "COMPUTER ETHICS AND HUMAN ISSUES: COMPUTER SECURITY"}, {"id": "objective>Computer Studies>2025 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A computer fails to boot and displays a message 'Boot device not found'. The user has verified that the hard drive is physically connected and powered on. Which of the following is the most likely cause of this error?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The computer's RAM is faulty.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The BIOS/UEFI boot order is incorrectly configured.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The computer's graphics card is not working.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The computer's power supply unit (PSU) is failing.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a computer displays the message \"Boot device not found\", it means that the system firmware (BIOS or UEFI) cannot locate a device with a valid operating system to start from. Since the user confirmed that the hard drive is physically connected and powered, the most common cause is an incorrect boot order setting. <br/>  <br/> RAM faulty: Faulty RAM can cause the computer to fail POST or crash, but it usually does not result in a \"boot device not found\" error. <br/>  <br/> Incorrect boot order: The BIOS/UEFI has a prioritized list of devices it checks to find bootable media. If the hard drive is not prioritized or is missing from the boot order, the system will fail to find an OS, even if the drive is fine. <br/>  <br/> Graphics card issue: Problems with the graphics card typically result in no video output or distorted display but do not prevent the system from detecting boot devices. <br/>  <br/> Power supply unit failing: A failing PSU usually causes power issues or unexpected shutdowns but would not specifically cause the boot device error if the hard drive powers on. <br/>  <br/> Therefore, reconfiguring the BIOS/UEFI boot order to ensure the hard drive is set as the primary boot device is the most likely fix for this error.</div>", "topic": "COMPUTER MAINTENANCE AND SAFETY MEASURES:BOOTING AND SHUTTING DOWN PROCESS :"}, {"id": "objective>Computer Studies>2025 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which type of software is embedded in hardware devices to provide low-level control and is not usually directly accessible by users?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Application software</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Utility software</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Firmware</div>", "<div style=\"font-family:Cambria;font-size:17px;\">System software</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Firmware is specialized software programmed into hardware devices such as routers, printers, and embedded systems. It provides low-level control, allowing the hardware to perform specific functions. Firmware sits between hardware and higher-level software but is generally not modified or accessed directly by end users.</div>", "topic": "FUNDAMENTALS OF COMPUTING: OVERVIEW OF COMPUTING SYSTEMS:TYPES, EXAMPLES AND USES OF SOFTWARE"}, {"id": "objective>Computer Studies>2025 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following scenarios is a practical example of a Metropolitan Area Network (MAN)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A network that connects a single home's computers to a router.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The network connecting all of a company's international offices across the world.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A network that connects a single person's smartphone, laptop, and smart speaker via Bluetooth.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A wireless network that connects a city's public transportation system, emergency services, and various government buildings.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Metropolitan Area Network (MAN) is designed to cover a large geographic area, typically spanning a city or metropolitan region. It connects multiple Local Area Networks (LANs) within that region, enabling high-speed communication across various facilities or organizations within the city.</div>", "topic": "INFORMATION & COMMUNICATION TECHNOLOGY (ICT):NETWORKING: NETWORK TYPES"}, {"id": "objective>Computer Studies>2025 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A user is writing a report and needs to apply the exact same font, size, bolding, and color from one heading to ten other headings in the document. What is the most efficient 'basic operation' to achieve this without manually changing each heading?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Manually applying a 'Quick Style' to each heading.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Using the 'Paste Special' option with 'Merge Formatting'.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Using 'Find and Replace' to replace the old formatting with the new one.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Using the 'Format Painter' tool.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Format Painter tool in MS Word is specifically designed to copy formatting from one piece of text and apply it to others quickly and efficiently. In this scenario, where a user wants to apply the exact same font, size, bolding, and color from one heading to multiple others, Format Painter saves time by allowing the user to: <br/>  <br/> Select the formatted heading as the source. <br/>  <br/> Click the Format Painter once to apply the formatting to one other heading, or double-click it to apply the formatting to multiple headings consecutively without needing to reactivate the tool each time. <br/>  <br/> This avoids the tedium of manually adjusting each heading's properties.</div>", "topic": "COMPUTER APPLICATION PACKAGES: WORD PROCESSING PACKAGE:MS WORD: BASIC OPERATIONS"}, {"id": "objective>Computer Studies>2025 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which scenario is using an interpreter more advantageous than using a compiler?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">When the program requires maximum runtime performance.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">When the development process involves frequent testing and debugging.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">When creating software that will be distributed without source code.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">When the program is very large and complex.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interpreters allow programmers to run and test code line-by-line without requiring the entire program to be compiled. This immediate feedback makes debugging and incremental development easier because errors can be identified and corrected quickly. It is especially useful in educational environments, scripting, or rapid prototyping. <br/>  <br/> Conversely, compilers generate an optimized executable that runs faster, making them better suited for production environments where performance is critical. Compiled programs also allow distribution without exposing the source code. For very large or complex programs, compilers offer efficiency and optimization benefits that interpreters cannot match.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: HIGH LEVEL LANGUAGES (HLL) : TRANSLATORS"}, {"id": "objective>Computer Studies>2025 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What does the term 'latency' mean in networking?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The maximum amount of data that can be sent over a network.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The delay between sending a data packet and receiving a response.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The total number of devices connected to a network.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The security level of a network connection.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Latency is the measure of time it takes for a data packet to travel from the sender to the receiver and for a response to return. It is typically measured in milliseconds (ms). High latency can cause noticeable delays in applications like online gaming, video conferencing, or VoIP calls. It is different from bandwidth, which refers to data capacity, and is unrelated to the number of devices or security.</div>", "topic": "INFORMATION & COMMUNICATION TECHNOLOGY (ICT):NETWORKING: DEFINITIONS"}, {"id": "objective>Computer Studies>2025 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A file is renamed from 'document.docx' to 'report.pdf'. Which of the following is the most accurate description of what happens to the file?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The file's content is automatically converted to the PDF format, and the file can now be opened with a PDF reader.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The file is now read-only and cannot be edited by the user.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The file's content remains in the DOCX format, but the operating system's association with the file is now for PDF applications.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The file becomes corrupt and can no longer be opened by any application.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a file is simply renamed from document.docx to report.pdf, only the file name and extension change. This action does not convert or alter the actual content of the file. The file data remains in the original DOCX format, which is a Microsoft Word document format. <br/>  <br/> However, because many operating systems use the file extension to determine which application to use when opening a file, changing the extension to .pdf will cause the system to try opening the file with a PDF reader. Since the content is not actually a PDF but still a DOCX, the PDF reader will typically fail to open it correctly, or it may show errors or garbage content.</div>", "topic": "MANAGING COMPUTER FILES: CONCEPT OF COMPUTER FILES:DEFINITIONS OF BASIC TERMS"}, {"id": "objective>Computer Studies>2025 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which sector is ICT primarily used to enhance supply chain management and inventory control?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Entertainment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the manufacturing sector, ICT systems play a crucial role in supply chain management and inventory control by automating processes such as ordering, tracking, and warehouse management. Technologies like RFID, barcode scanning, and Enterprise Resource Planning (ERP) software allow manufacturers to monitor stock levels in real time, predict demand, and optimize production schedules. While agriculture and education benefit from ICT, the specific function of optimizing supply chains is most critical and extensively applied in manufacturing.</div>", "topic": "INFORMATION & COMMUNICATION TECHNOLOGY (ICT):APPLICATION AREAS OF ICT : APPLICATION AREAS"}, {"id": "objective>Computer Studies>2025 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A project manager decides to skip the Analysis phase to speed up the development of a new system. What is the most likely and critical consequence of this decision?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The system will be less secure because security requirements were not defined.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The project will be canceled due to a lack of a feasibility study.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The project will be completed ahead of schedule and under budget.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The final system will not meet the users' needs and will likely fail to solve the original business problem.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Analysis phase of the SDLC is crucial because it involves thoroughly understanding and documenting the users' requirements and the business problems the system must address. Skipping this phase means the development team lacks a clear understanding of what the system is supposed to accomplish, leading to a mismatch between the delivered system and actual user needs. <br/>  <br/> While it might seem that skipping analysis could speed up the project, this short-term gain is usually outweighed by long-term consequences. The system may lack essential features, have poor usability, or fail to integrate properly with existing processes, resulting in user dissatisfaction or rejection. Fixing these issues post-development is often more costly and time-consuming than a proper analysis upfront.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: SYSTEM DEVELOPMENT LIFE CYCLE (SDLC) : STAGES OF SDLC"}, {"id": "objective>Computer Studies>2025 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The invention of the microprocessor, particularly the Intel 4004 in 1971, is credited with ushering in the fourth generation of computers. What was the <strong>most</strong> profound change this invention brought to the computing landscape?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It allowed computers to be built entirely with Integrated Circuits (ICs).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It replaced the use of punch cards with magnetic tape for data storage.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It consolidated the Central Processing Unit (CPU) onto a single chip, making computers small and affordable enough for personal use.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It enabled the development of supercomputers for scientific research.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The invention of the microprocessor, exemplified by the Intel 4004 in 1971, marked a revolutionary advancement in computing. Prior to this, CPUs were built using multiple integrated circuits or discrete components. The Intel 4004 was the first single-chip CPU, integrating all the processing functions into one compact unit. <br/>  <br/> This consolidation dramatically reduced the size, cost, and power consumption of computers, which paved the way for the development of personal computers (PCs) and embedded systems. Computers became accessible to businesses, schools, and eventually individuals, transforming computing from a specialized, expensive activity into a widespread everyday tool.</div>", "topic": "EVOLUTION OF COMPUTING: HISTORY OF COMPUTING:COMPUTING DEVICES - 20TH CENTURY"}, {"id": "objective>Computer Studies>2025 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hospital requires a software system that manages patient records, schedules appointments, and handles billing specifically for medical services. This software is a prime example of which type of application package?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Specific-purpose software.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General-purpose software.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">System software.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Utility software.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The software described—managing patient records, scheduling appointments, and handling billing specifically for medical services—is tailored to the unique needs of the healthcare industry. This type of software is known as specific-purpose software, also called vertical software, because it targets a particular industry or specialized function. <br/>  <br/> Specific-purpose software is designed to address the unique workflows, terminology, and regulations of a given sector (like healthcare, banking, or manufacturing), offering features that general software cannot provide out-of-the-box. For example, it might include modules for electronic health records (EHR), insurance claims, or compliance with medical standards. <br/>  <br/> General-purpose software, on the other hand, includes applications like word processors, spreadsheets, or email clients that serve broad user needs across many industries. <br/>  <br/> System software refers to software that manages and controls hardware and provides a platform for running application software, such as operating systems and device drivers. <br/>  <br/> Utility software is designed to perform maintenance or optimization tasks on a computer, such as antivirus or disk cleanup tools. <br/>  <br/> Therefore, the hospital's software is a perfect example of specific-purpose software because it is customized for medical service management, meeting specialized demands that general software cannot fulfill efficiently.</div>", "topic": "COMPUTER APPLICATION PACKAGES: GENERAL CONCEPT"}, {"id": "objective>Computer Studies>2025 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a key <strong>disadvantage</strong> of using a High-Level Language (HLL) compared to a low-level language like assembly?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HLLs are not portable and can only be run on the machine they were compiled on.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HLLs are more difficult to read and understand, increasing the likelihood of errors.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HLLs can only be used for simple tasks, while low-level languages are used for complex tasks.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HLLs offer less control over the computer's hardware, and the resulting machine code is generally less efficient and slower to execute.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">While high-level languages (HLLs) provide abstraction, ease of use, and portability, one of their key disadvantages compared to low-level languages like assembly is that they offer less direct control over hardware resources such as CPU registers, memory addresses, and hardware interrupts. This abstraction can lead to machine code that is less optimized and therefore runs slower or uses more resources than hand-crafted assembly code.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: HIGH LEVEL LANGUAGES (HLL) : CHARACTERISTICS OF HLL"}, {"id": "objective>Computer Studies>2025 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which database organization does a record potentially have multiple parent records, creating a graph structure rather than a strict hierarchy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Flat file database</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hierarchical database</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Network database</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Relational database</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The network database model allows a record to have multiple parent records, forming a graph or mesh structure rather than a strict tree hierarchy. This flexibility enables representation of many-to-many relationships that are difficult to model in hierarchical databases. The network model uses sets and pointers to connect related records, making data access more complex but more powerful for certain applications.</div>", "topic": "COMPUTER APPLICATION PACKAGES: DATABASE PACKAGE:DATABASE ORGANIZATIONS"}, {"id": "objective>Computer Studies>2025 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A writer is collaborating on a document with an editor. The editor wants to suggest changes without permanently altering the original text. Which feature is specifically designed for this purpose?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Macros</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Track Changes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Version History</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Document Inspector</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Track Changes feature in word processing software is specifically designed for collaborative editing. When enabled, it records all modifications—such as insertions, deletions, and formatting changes—made by the editor without permanently altering the original text. These changes are visually marked (often with colored underlines, strikethroughs, or balloons) so the original author can review, accept, or reject each edit. This facilitates transparent collaboration by preserving the original content and clearly showing proposed changes.</div>", "topic": "COMPUTER APPLICATION PACKAGES: WORD PROCESSING PACKAGE:GENERAL CONCEPT"}, {"id": "objective>Computer Studies>2025 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A programmer is developing a device driver for a new graphics card. Which class of programming language would be the most suitable choice, and why?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A high-level language like Python, because it is easy to write.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A high-level language like Java, because it is portable.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A low-level language like Assembly, because it offers direct control over hardware and memory for performance-critical tasks.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A scripting language like JavaScript, because it is easy to debug.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When developing a device driver, especially for hardware like a graphics card, direct and precise control over hardware resources and memory is essential. Low-level languages such as Assembly allow programmers to write instructions that interact closely with the hardware, manipulate registers, handle interrupts, and optimize performance-critical routines.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: PROGRAMMING LANGUAGE (PL) : DEFINITION AND CLASSIFICATION OF PL"}, {"id": "objective>Computer Studies>2025 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company uses a file-based system for customer records. To search for a specific customer, the system must read every record from the beginning of the file until the correct record is found. Which of the following is the most significant disadvantage of this file access method?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It requires a large amount of memory to store the entire file.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is a very slow method for finding a record in a large file.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is susceptible to data corruption if the file is not sorted.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It does not allow new records to be added to the file.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scenario describes a sequential access method, where the system reads each record from the start until it finds the desired one. This approach can be extremely inefficient, especially when dealing with large files, because the time to find a record grows linearly with the number of records. Every search potentially requires scanning many irrelevant records first, leading to long wait times.</div>", "topic": "MANAGING COMPUTER FILES: CONCEPT OF COMPUTER FILES:METHODS OF ACCESSING FILES"}, {"id": "objective>Computer Studies>2025 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A database administrator needs to ensure that a 'CustomerID' field contains only unique, non-null values. Which of the following database features is the most appropriate for enforcing this rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A Foreign Key constraint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A CHECK constraint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A Primary Key constraint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An INDEX</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Primary Key constraint is specifically designed to enforce uniqueness and non-nullability on a field or a combination of fields within a database table. When a column is defined as a primary key, it guarantees that no two rows can have the same value in that column and that the value cannot be null. This is essential for uniquely identifying each record in the table.</div>", "topic": "COMPUTER APPLICATION PACKAGES: DATABASE PACKAGE:DIFFERENT FEATURES OF DATABASE FORMAT"}, {"id": "objective>Computer Studies>2025 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which type of communication system allows real-time interaction and transmission of data between users at different locations, commonly used in video conferencing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Broadcast communication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Point-to-point communication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Asynchronous communication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Multipoint communication</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Point-to-point communication involves a direct connection between two devices or users, enabling real-time data exchange. In video conferencing, a dedicated communication link connects participants, allowing simultaneous sending and receiving of audio and video signals with minimal delay. This system contrasts with broadcast communication, which sends data to many receivers simultaneously but without interactive feedback.</div>", "topic": "INFORMATION & COMMUNICATION TECHNOLOGY (ICT):COMMUNICATION SYSTEMS : TYPES AND EXAMPLES OF ICT"}, {"id": "objective>Computer Studies>2025 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A software team is developing a critical system for air traffic control. During the design phase, which of the following precautions is most crucial to ensure the system is both reliable and maintainable in the long term?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prioritizing the use of a single, simple programming language.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Writing the code first and documenting it after the project is complete.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adhering strictly to established design patterns and documenting the architecture before any code is written.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Focusing solely on the user interface to ensure a positive user experience.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a critical system, adhering to established design patterns and comprehensive documentation during the design phase is paramount. Design patterns are proven solutions to common problems, and their use ensures the system is well-structured, robust, and understandable to other developers. Documenting the architecture before coding starts provides a clear blueprint, which is essential for managing complexity, ensuring reliability, and making the system maintainable over its lifespan. Writing code first or focusing only on the UI are both common pitfalls that lead to poorly structured, difficult-to-maintain software.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: PROGRAM DEVELOPMENT : PRECAUTIONS"}, {"id": "objective>Computer Studies>2025 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A meteorological institute needs a computing device that can handle petabytes of data, perform complex climate simulations, and run thousands of parallel calculations simultaneously. Which category of computer would be the most suitable, and what is its primary characteristic that enables this capability?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Microcomputer, characterized by a single Central Processing Unit (CPU).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mainframe, characterized by its ability to process a single, massive task efficiently.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supercomputer, characterized by its ability to perform massively parallel processing.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Workstation, characterized by its high-end graphics processing unit (GPU).</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Supercomputers are the most powerful class of computing devices, specifically designed for tasks that require enormous computational power and data handling capabilities, such as climate modeling, meteorological simulations, and scientific research. Their primary characteristic is massively parallel processing—the use of thousands or even millions of processors working simultaneously to perform complex calculations much faster than traditional computers.</div>", "topic": "EVOLUTION OF COMPUTING: CLASSIFICATION OF COMPUTING DEVICES:BY SIZE"}, {"id": "objective>Computer Studies>2025 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which type of computer system is commonly found inside household appliances and vehicles, performing specific control functions?  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">General-purpose computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Embedded system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Workstation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Minicomputer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Embedded systems are integral components of household appliances (like microwaves and washing machines), automobiles (engine control units), and industrial machines. These systems operate dedicated software to control hardware functions and often run with real-time constraints. Their design focuses on reliability, efficiency, and long-term operation within the specific context of the device, differentiating them from general-purpose computers that support a wide range of applications.</div>", "topic": "EVOLUTION OF COMPUTING: CLASSIFICATION OF COMPUTING DEVICES:BY TYPE"}, {"id": "objective>Computer Studies>2025 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the purpose of quantization in the digitization of an analog signal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To take measurements of the analog signal at regular intervals.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To assign a discrete numerical value to each sampled measurement.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To compress the digital data to reduce file size.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To convert the digital signal back into an analog signal.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quantization is a critical step in the digitization of analog signals that follows sampling. While sampling takes measurements of the analog signal at regular time intervals (Option A), these measurements are still continuous in amplitude. Quantization converts these continuous amplitude values into discrete numerical levels by assigning each sampled measurement to the nearest fixed value within a finite set of possible values. This process allows the analog signal's varying amplitudes to be represented in digital form, typically as binary numbers, enabling storage, processing, and transmission by digital systems. <br/>  <br/> Without quantization, the sampled values would still be analog and could not be handled efficiently by digital devices. However, quantization introduces a small amount of error called quantization noise because the continuous signal is approximated by discrete levels. The precision of quantization depends on the number of discrete levels (bit depth) — more levels mean less error but larger data sizes. <br/>  <br/> In contrast, Option C refers to data compression, which happens after digitization to reduce file size, and Option D describes digital-to-analog conversion, which is the reverse process of digitization. Thus, the main purpose of quantization is best described by Option B.</div>", "topic": "FUNDAMENTALS OF COMPUTING: DATA AND INFORMATION :METHODS OF DIGITISATION"}, {"id": "objective>Computer Studies>2025 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the primary purpose of the System Development Life Cycle (SDLC)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To provide a structured framework for designing and managing system projects.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To manage the installation of hardware and network devices in a system.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To document user manuals and operational guides after system completion.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To schedule software releases and updates without planning development.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The SDLC provides a comprehensive framework that guides the entire process of system creation, from initial concept through deployment and maintenance. This framework ensures that projects follow a well-defined path, allowing for proper planning, requirement gathering, system design, implementation, testing, and ongoing maintenance. It addresses critical project management needs, risk reduction, and quality assurance. Unlike options B and C, SDLC covers more than hardware installation or just documentation, and unlike D, it emphasizes thorough planning, not ad hoc scheduling.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: SYSTEM DEVELOPMENT LIFE CYCLE (SDLC) : DEFINITION OF SDCL"}, {"id": "objective>Computer Studies>2025 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which classification of high-level language is characterized by writing instructions as sequences of statements executed one after the other?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Procedural Languages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Functional Languages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Logic Languages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Declarative Languages</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Procedural languages are characterized by writing instructions as ordered sequences - telling the computer how to perform tasks step by step. This contrasts with declarative languages, which describe what the outcome should be, and functional and logic languages, which emphasize functions and logical relations respectively. Procedural languages provide explicit control flow structures like loops, conditionals, and procedure calls.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: HIGH LEVEL LANGUAGES (HLL) : CLASSIFICATIONS OF HLL"}, {"id": "objective>Computer Studies>2025 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the first essential step in developing a program?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Writing the source code in a chosen programming language.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Designing the user interface and screen layouts.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Testing the program to find and fix errors.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Understanding and analyzing the problem requirements thoroughly.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Before writing any code, the developer must fully understand what the program is supposed to achieve. This involves analyzing the problem, gathering detailed requirements, and identifying constraints. This foundational step guides all subsequent activities. Skipping or rushing this phase leads to misunderstandings and errors in design and coding. Writing code comes later, testing occurs after development, and designing UI is part of system design but only after requirements are clear.</div>", "topic": "DEVELOPING PROBLEM-SOLVING SKILLS: PROGRAM DEVELOPMENT : STEPS INVOLVED IN DEVELOPING PROGRAM"}, {"id": "objective>Computer Studies>2025 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best describes 'cyberstalking'?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Using a computer to send threatening messages repeatedly to an individual.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hacking into someone's social media accounts to post defamatory content.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stealing sensitive information through network intrusion.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sending unsolicited marketing emails to many users.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cyberstalking is the use of electronic communication to harass, intimidate, or threaten someone persistently. It often involves sending threatening or unwanted messages repeatedly. Hacking and data theft are different crimes, while unsolicited marketing emails relate more to spamming.</div>", "topic": "COMPUTER ETHICS AND HUMAN ISSUES: ETHICAL ISSUES : COMPUTER–RELATED CRIME"}];
